// 多叉树节点 class Node { public:  int val;  vector<Node*> children; };

// 多叉树的遍历框架 void traverse(Node* root) {  // base case  if (root == nullptr) {  return;  }  // 前序位置  cout << "visit " << root->val << endl;  for (auto child : root->children) {  traverse(child);  }  // 后序位置 }

// 图节点 class Vertex { public:  int id;  vector<Vertex*> neighbors; };

// 图的遍历框架 // 需要一个 visited 数组记录被遍历过的节点 // 避免走回头路陷入死循环 void traverse(Vertex* s, vector<bool>& visited) {  // base case  if (s == nullptr) {  return;  }  if (visited[s->id]) {  // 防止死循环  return;  }  // 前序位置  visited[s->id] = true;  cout << "visit " << s->id << endl;  for (auto neighbor : s->neighbors) {  traverse(neighbor, visited);  }  // 后序位置 }

// 多叉树节点 class Node { public:  int val;  vector<Node*> children;  Node(int v = 0) : val(v) {} };

// 遍历多叉树的树枝 void traverseBranch(Node* root) {  // base case  if (root == nullptr) {  return;  }  for (Node* child : root->children) {  cout << "visit branch: " << root->val << " -> " << child->val << endl;  traverseBranch(child);  } }

// 图节点 class Vertex { public:  int id;  vector<Vertex*> neighbors;  Vertex(int i = 0) : id(i) {} };

// 遍历图的边 // 需要一个二维 visited 数组记录被遍历过的边，visited[u][v] 表示边 u->v 已经被遍历过 void traverseEdges(Vertex* s, vector<vector<bool>>& visited) {  // base case  if (s == nullptr) {  return;  }  for (Vertex* neighbor : s->neighbors) {  // 如果边已经被遍历过，则跳过  if (visited[s->id][neighbor->id]) {  continue;  }  // 标记并访问边  visited[s->id][neighbor->id] = true;  cout << "visit edge: " << s->id << " -> " << neighbor->id << endl;  traverseEdges(neighbor, visited);  } }
